const amqp = require('amqplib/callback_api');

amqp.connect('amqp://localhost', (err, conn) => {
  if (err) throw err;

  conn.createChannel((err, ch) => {
    if (err) throw err;

    const queue = 'payment_queue';

    ch.assertQueue(queue, { durable: true });

    console.log('Waiting for messages in %s. To exit press CTRL+C', queue);

    ch.consume(queue, (msg) => {
      if (msg !== null) {
        try {
          const paymentEvent = JSON.parse(msg.content.toString());

          // Execute payment logic based on message content
          processPayment(paymentEvent);

          ch.ack(msg);
        } catch (error) {
          console.error('Error processing message:', error);
          ch.nack(msg, false, true); // Reject message with requeue
        }
      }
    }, { noAck: false });
  });
});

function processPayment(paymentEvent) {
  console.log('Processing payment event:', paymentEvent);

  // Implement your payment logic here
  // For example:
  if (paymentEvent.amount > 0) {
    console.log('Payment processed successfully for amount:', paymentEvent.amount);
  } else {
    throw new Error('Invalid payment amount');
  }
}